import{_ as r,o as e,c as t,ag as l}from"./chunks/framework.CbQjVMS6.js";const u=JSON.parse('{"title":"Pai‑RAG 项目：最终建议写进简历的 6 个亮点（5–7 点区间 ✅）","description":"","frontmatter":{},"headers":[],"relativePath":"Resume/2.14.1.md","filePath":"Resume/2.14.1.md","lastUpdated":null}'),i={name:"Resume/2.14.1.md"};function o(n,a,s,p,g,c){return e(),t("div",null,[...a[0]||(a[0]=[l('<p>收到 ✅ 你这 3 个文件我已经完整读完了：</p><ul><li><p><strong>2.13.2.md</strong>：你最初的简历草稿（确实存在“技术栈/实现点”不对齐教程的问题）</p></li><li><p><strong>1.txt</strong>：你之前那版“亮点 + 14 天计划”的草稿（有价值，但有几处硬伤要修正）</p></li><li><p><strong>2.txt</strong>：偏“断点调试式吃透项目”的 14 天游学攻略（方向对，但也要对齐真实技术栈）</p></li></ul><p>你问的两个核心问题，我给明确结论：</p><h2 id="结论-14-天游学计划要改-而且改完能-100-匹配你的简历亮点-✅" tabindex="-1">结论：14 天游学计划要改，而且改完能 100% 匹配你的简历亮点 ✅ <a class="header-anchor" href="#结论-14-天游学计划要改-而且改完能-100-匹配你的简历亮点-✅" aria-label="Permalink to &quot;结论：14 天游学计划要改，而且改完能 100% 匹配你的简历亮点 ✅&quot;">​</a></h2><p>原因很简单：你简历里目前写的 <strong>Milvus / SSE / RRF</strong> 这条线，和派聪明教程公开说明的实际方案 <strong>不一致</strong>。<br> 派聪明后端技术栈明确写的是：<strong>Elasticsearch 8.10.0、Kafka、MinIO+Tika、Spring Security+JWT、WebSocket、WebFlux、MySQL、Redis、DeepSeek、豆包 Embedding</strong>，并没有把 Milvus 作为落地必选项。(<a href="https://paicoding.com/column/10/1" title="✅派聪明 RAG 知识库项目上线了！AI 时代，你值得拥有！ - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</p><p>所以：</p><ul><li><p><strong>简历必须改</strong>（否则面试官一追问，“你 Milvus 怎么建 collection？怎么写 partition？你们 ES/向量数据到底存哪？” 你会原地爆炸💥）</p></li><li><p><strong>14 天计划也必须改</strong>（否则你学了 Milvus/SSE 那套，跟项目真实代码对不上）</p></li></ul><hr><h2 id="先把-简历里的硬伤-当场纠正-你提到要我辨别错误-这里直接点名" tabindex="-1">先把“简历里的硬伤”当场纠正（你提到要我辨别错误，这里直接点名） <a class="header-anchor" href="#先把-简历里的硬伤-当场纠正-你提到要我辨别错误-这里直接点名" aria-label="Permalink to &quot;先把“简历里的硬伤”当场纠正（你提到要我辨别错误，这里直接点名）&quot;">​</a></h2><h3 id="你原简历-2-13-2-md-里高风险点" tabindex="-1">你原简历（2.13.2.md）里高风险点 <a class="header-anchor" href="#你原简历-2-13-2-md-里高风险点" aria-label="Permalink to &quot;你原简历（2.13.2.md）里高风险点&quot;">​</a></h3><ol><li><p><strong>Milvus</strong>：派聪明教程说明的“搜索引擎/向量检索”是 <strong>Elasticsearch（dense_vector）</strong>，向量也“目前存 ES”。(<a href="https://paicoding.com/column/10/1" title="✅派聪明 RAG 知识库项目上线了！AI 时代，你值得拥有！ - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</p></li><li><p><strong>SSE</strong>：聊天助手模块设计方案写的是 <strong>WebSocket 双向通信 + 流式输出</strong>。(<a href="https://paicoding.com/column/10/16" title="✅派聪明 RAG 系统的聊天助手模块设计方案 - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</p></li><li><p><strong>RRF 倒数融合</strong>：检索模块设计方案描述的是“语义 + 关键词结合、按权重排序返回”，以及 ES 混合检索思路；并非教程明确要求你实现 RRF。(<a href="https://paicoding.com/column/10/15%3Bjsessionid%3D2547B2D7F523EE083B197FD530342004" title="✅派聪明 RAG知识库检索模块设计方案 - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</p></li></ol><p>这三条如果不改，属于“简历写得越酷，面试死得越快”的典型 😵‍💫</p><hr><h2 id="我已经帮你把简历改成-对齐教程且更能打-的版本-可直接替换" tabindex="-1">我已经帮你把简历改成“对齐教程且更能打”的版本（可直接替换） <a class="header-anchor" href="#我已经帮你把简历改成-对齐教程且更能打-的版本-可直接替换" aria-label="Permalink to &quot;我已经帮你把简历改成“对齐教程且更能打”的版本（可直接替换）&quot;">​</a></h2><p>📄 <strong>下载你更新后的简历文件（V4.0 对齐教程版）</strong>：<br><a href="sandbox:/mnt/data/2.13.2_v4.md" target="_blank" rel="noreferrer">Download 2.13.2_v4.md</a></p><blockquote><p>这个版本重点把 Pai‑RAG 写成你简历的压轴曲🎸，并且把 Milvus/SSE/RRF 这类不对齐内容删掉了。</p></blockquote><hr><h1 id="pai‐rag-项目-最终建议写进简历的-6-个亮点-5–7-点区间-✅" tabindex="-1">Pai‑RAG 项目：最终建议写进简历的 6 个亮点（5–7 点区间 ✅） <a class="header-anchor" href="#pai‐rag-项目-最终建议写进简历的-6-个亮点-5–7-点区间-✅" aria-label="Permalink to &quot;Pai‑RAG 项目：最终建议写进简历的 6 个亮点（5–7 点区间 ✅）&quot;">​</a></h1><p>下面这 <strong>6 点</strong>就是你简历里最值得保留的“面试可深挖亮点”。我同时把<strong>每一点对应的教程/方案出处</strong>标注出来（按你要求来）。</p><hr><h2 id="亮点-1-gb-级大文件分片上传-断点续传-minio-redis-bitmap" tabindex="-1">亮点 1｜GB 级大文件分片上传 + 断点续传（MinIO + Redis Bitmap） <a class="header-anchor" href="#亮点-1-gb-级大文件分片上传-断点续传-minio-redis-bitmap" aria-label="Permalink to &quot;亮点 1｜GB 级大文件分片上传 + 断点续传（MinIO + Redis Bitmap）&quot;">​</a></h2><p><strong>简历写法（建议）</strong>：</p><ul><li>设计分片上传链路：客户端计算文件 MD5，分片落 MinIO；使用 **Redis Bitmap（SETBIT）**记录分片进度；分片齐备后通过 <strong>MinIO composeObject</strong> 在存储端合并，避免服务端内存/CPU 压力，提升大文件上传可靠性与体验。</li></ul><p><strong>对应内容出处</strong>：</p><ul><li><p>文件上传解析设计方案：分片、断点续传、MinIO + Redis、合并流程 (<a href="https://paicoding.com/column/10/14" title="✅派聪明 RAG 项目文件上传解析模块设计方案 - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</p></li><li><p>文件上传解析面试题预测：Bitmap 记录进度、composeObject 合并细节讲得非常直白 (<a href="https://paicoding.com/column/10/22?utm_source=chatgpt.com" title="派聪明 RAG 文件上传解析面试题预测，19 道，覆盖 Kafka ..." target="_blank" rel="noreferrer">技术派</a>)</p></li></ul><hr><h2 id="亮点-2-kafka-异步流水线解耦-上传快返回、解析-向量化后台跑" tabindex="-1">亮点 2｜Kafka 异步流水线解耦：上传快返回、解析/向量化后台跑 <a class="header-anchor" href="#亮点-2-kafka-异步流水线解耦-上传快返回、解析-向量化后台跑" aria-label="Permalink to &quot;亮点 2｜Kafka 异步流水线解耦：上传快返回、解析/向量化后台跑&quot;">​</a></h2><p><strong>简历写法（建议）</strong>：</p><ul><li>合并完成后发送解析任务到 Kafka；解析服务消费后按文件类型调用 Tika 提取文本并切分，再发送向量化任务到 Kafka，实现文档处理链路异步化与削峰填谷。</li></ul><p><strong>对应内容出处</strong>：</p><ul><li>上传解析模块完整数据流：合并→Kafka→解析→切分→Kafka→向量化→写 ES (<a href="https://paicoding.com/column/10/14" title="✅派聪明 RAG 项目文件上传解析模块设计方案 - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</li></ul><hr><h2 id="亮点-3-多格式解析-文本切分-embedding-向量化入库-向量-目前存-es" tabindex="-1">亮点 3｜多格式解析 + 文本切分 + Embedding 向量化入库（向量“目前存 ES”） <a class="header-anchor" href="#亮点-3-多格式解析-文本切分-embedding-向量化入库-向量-目前存-es" aria-label="Permalink to &quot;亮点 3｜多格式解析 + 文本切分 + Embedding 向量化入库（向量“目前存 ES”）&quot;">​</a></h2><p><strong>简历写法（建议）</strong>：</p><ul><li>支持 PDF/Word/Excel 等多格式文档解析（Tika），对文本分块后调用 <strong>豆包 Embedding API</strong> 生成向量；向量与 chunk 元信息写入 <strong>Elasticsearch</strong>（并预留 FAISS 扩展接口）。</li></ul><p><strong>对应内容出处</strong>：</p><ul><li>文件上传解析模块：明确写了 Tika、多格式、豆包向量、向量目前存 ES、预留 FAISS (<a href="https://paicoding.com/column/10/14" title="✅派聪明 RAG 项目文件上传解析模块设计方案 - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</li></ul><hr><h2 id="亮点-4-elasticsearch-混合检索-ik-bm25-dense-vector-语义检索-可控-topk" tabindex="-1">亮点 4｜Elasticsearch 混合检索：IK/BM25 + dense_vector 语义检索（可控 topK） <a class="header-anchor" href="#亮点-4-elasticsearch-混合检索-ik-bm25-dense-vector-语义检索-可控-topk" aria-label="Permalink to &quot;亮点 4｜Elasticsearch 混合检索：IK/BM25 + dense_vector 语义检索（可控 topK）&quot;">​</a></h2><p><strong>简历写法（建议）</strong>：</p><ul><li>基于 ES 实现 <strong>关键词检索（IK/BM25）+ 向量语义检索（dense_vector）</strong> 的混合召回，按权重排序并支持 topK 控制返回数量，提升语义近似与专有名词场景的综合命中。</li></ul><p><strong>对应内容出处</strong>：</p><ul><li><p>检索模块设计方案：明确“基于 Elasticsearch 的混合检索，语义+关键词结合，按权重排序、topK”，并且该模块直接检索 ES 中的向量数据 (<a href="https://paicoding.com/column/10/15%3Bjsessionid%3D2547B2D7F523EE083B197FD530342004" title="✅派聪明 RAG知识库检索模块设计方案 - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</p></li><li><p>ES 混合检索精讲：解释关键词检索/语义检索的组合动机（足够支撑面试讲原理） (<a href="https://paicoding.com/column/10/27" title="✅派聪明 RAG 项目的ElasticSearch混合检索精讲 - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</p></li></ul><hr><h2 id="亮点-5-企业级-rbac-spring-security-jwt-组织标签-orgtags-隔离数据" tabindex="-1">亮点 5｜企业级 RBAC：Spring Security + JWT + 组织标签（orgTags）隔离数据 <a class="header-anchor" href="#亮点-5-企业级-rbac-spring-security-jwt-组织标签-orgtags-隔离数据" aria-label="Permalink to &quot;亮点 5｜企业级 RBAC：Spring Security + JWT + 组织标签（orgTags）隔离数据&quot;">​</a></h2><p><strong>简历写法（建议）</strong>：</p><ul><li>基于 Spring Security 过滤器链实现认证/授权，使用 JWT 无状态登录；引入组织标签（orgTags）模型，在检索阶段加入权限过滤条件，实现跨组织/私有资源隔离。</li></ul><p><strong>对应内容出处</strong>：</p><ul><li><p>RBAC 教程：Spring Security 的 Filter 链、认证授权、角色模型等 (<a href="https://paicoding.com/column/10/28" title="✅如何基于Spring Security实现派聪明 RAG 知识库的RBAC 权限系统？ - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</p></li><li><p>接口文档：登录/获取用户信息里包含 role、orgTags、primaryOrg 等字段（这是你“组织标签权限”的证据）(<a href="https://paicoding.com/column/10/18" title="✅派聪明 RAG 系统的接口文档 - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</p></li><li><p>检索模块设计方案：检索模块本身就包含“权限控制：基于组织标签的数据权限” (<a href="https://paicoding.com/column/10/15%3Bjsessionid%3D2547B2D7F523EE083B197FD530342004" title="✅派聪明 RAG知识库检索模块设计方案 - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</p></li></ul><hr><h2 id="亮点-6-websocket-流式问答-prompt-构建-buildmessages-redis-会话上下文" tabindex="-1">亮点 6｜WebSocket 流式问答 + Prompt 构建（buildMessages）+ Redis 会话上下文 <a class="header-anchor" href="#亮点-6-websocket-流式问答-prompt-构建-buildmessages-redis-会话上下文" aria-label="Permalink to &quot;亮点 6｜WebSocket 流式问答 + Prompt 构建（buildMessages）+ Redis 会话上下文&quot;">​</a></h2><p><strong>简历写法（建议）</strong>：</p><ul><li>聊天模块采用 WebSocket 双向通信，对接 DeepSeek Stream 实现“打字机式”流式输出；Prompt 使用配置化模板，并在 buildMessages 中拼装规则、检索片段与历史对话；会话上下文由 Redis 存储并设置过期策略，保障多轮对话连贯性。</li></ul><p><strong>对应内容出处</strong>：</p><ul><li><p>聊天助手模块设计方案：WebSocket 双向通信 + 流式返回 + Redis 维护会话上下文 (<a href="https://paicoding.com/column/10/16" title="✅派聪明 RAG 系统的聊天助手模块设计方案 - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</p></li><li><p>Prompt 设计：明确提到 buildMessages、动态拼装 system/user/assistant/检索上下文等 (<a href="https://paicoding.com/column/10/26?utm_source=chatgpt.com" title="派聪明 RAG 知识库的Prompt设计 - 技术派 - Java技术社区 ..." target="_blank" rel="noreferrer">技术派</a>)</p></li></ul><hr><h1 id="你的-14-天吃透项目计划-我也已经按真实技术栈重做了-完全对齐上面-6-个亮点" tabindex="-1">你的“14 天吃透项目计划”我也已经按真实技术栈重做了（完全对齐上面 6 个亮点） <a class="header-anchor" href="#你的-14-天吃透项目计划-我也已经按真实技术栈重做了-完全对齐上面-6-个亮点" aria-label="Permalink to &quot;你的“14 天吃透项目计划”我也已经按真实技术栈重做了（完全对齐上面 6 个亮点）&quot;">​</a></h1><p>下面这份计划的目标很明确：<br> ✅ <strong>不是 14 天游手搓项目</strong><br> ✅ 是 14 天把“关键链路 + 关键代码 + 关键证据 + 面试话术”吃干抹净<br> ✅ 每一天都有“必须产出物”（你会留下截图/笔记/证据包，面试能翻出来讲）</p><blockquote><p>每天建议时间：<strong>3 小时</strong>（2h 动手 + 1h 复盘输出）。周末可拉到 4–5 小时用来补齐“证据包”。</p></blockquote><hr><h2 id="day-1-建立全局视角-系统架构-数据流-必须画出-1-张图" tabindex="-1">Day 1｜建立全局视角：系统架构 + 数据流（必须画出 1 张图） <a class="header-anchor" href="#day-1-建立全局视角-系统架构-数据流-必须画出-1-张图" aria-label="Permalink to &quot;Day 1｜建立全局视角：系统架构 + 数据流（必须画出 1 张图）&quot;">​</a></h2><p><strong>任务</strong></p><ul><li><p>按教程技术栈确认你本地跑起来的组件：MySQL、Redis、Kafka、ES、MinIO、后端、前端</p></li><li><p>画一张“文件上传→入库→检索→问答”的数据流图（用 Markdown/纸笔都行）</p></li></ul><p><strong>产出物</strong></p><ul><li>1 张数据流图（必须包含：MD5 → Redis Bitmap → MinIO compose → Kafka(解析) → Tika → Kafka(向量化) → Embedding → ES → Chat Prompt → WebSocket Stream）<br><strong>对齐亮点</strong>：1/2/3/4/6</li></ul><hr><h2 id="day-2-用户与权限-把-rbac-链路跑通-别怕-security-怕的是你不敢碰" tabindex="-1">Day 2｜用户与权限：把 RBAC 链路跑通（别怕 Security，怕的是你不敢碰） <a class="header-anchor" href="#day-2-用户与权限-把-rbac-链路跑通-别怕-security-怕的是你不敢碰" aria-label="Permalink to &quot;Day 2｜用户与权限：把 RBAC 链路跑通（别怕 Security，怕的是你不敢碰）&quot;">​</a></h2><p><strong>任务</strong></p><ul><li><p>用接口文档把：注册→登录→拿 token→访问 /me 跑通</p></li><li><p>在后端断点跟一下 Spring Security Filter 链：token 从哪解析、UserContext 怎么塞进去</p></li></ul><p><strong>产出物</strong></p><ul><li>1 张“请求进来 → JWT 解析 → 认证/授权 → ThreadLocal/Context”的流程笔记<br><strong>对齐亮点</strong>：5 (<a href="https://paicoding.com/column/10/28" title="✅如何基于Spring Security实现派聪明 RAG 知识库的RBAC 权限系统？ - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</li></ul><hr><h2 id="day-3-分片上传-看见-redis-bitmap-的-setbit-这是你简历最硬的证据之一" tabindex="-1">Day 3｜分片上传：看见 Redis Bitmap 的 setbit（这是你简历最硬的证据之一） <a class="header-anchor" href="#day-3-分片上传-看见-redis-bitmap-的-setbit-这是你简历最硬的证据之一" aria-label="Permalink to &quot;Day 3｜分片上传：看见 Redis Bitmap 的 setbit（这是你简历最硬的证据之一）&quot;">​</a></h2><p><strong>任务</strong></p><ul><li><p>找到 upload / chunk upload 相关 Controller</p></li><li><p>上传一个会触发分片的文件（不要太大，先能触发即可）</p></li><li><p>断点停在“写 Redis Bitmap”的位置，记录 key 设计（通常是 fileMd5）</p></li></ul><p><strong>产出物</strong></p><ul><li>Redis 里对应 key 的截图/记录（证明 Bitmap 存在）<br><strong>对齐亮点</strong>：1 (<a href="https://paicoding.com/column/10/22?utm_source=chatgpt.com" title="派聪明 RAG 文件上传解析面试题预测，19 道，覆盖 Kafka ..." target="_blank" rel="noreferrer">技术派</a>)</li></ul><hr><h2 id="day-4-minio-合并-确认-composeobject-真在存储端完成" tabindex="-1">Day 4｜MinIO 合并：确认 composeObject 真在存储端完成 <a class="header-anchor" href="#day-4-minio-合并-确认-composeobject-真在存储端完成" aria-label="Permalink to &quot;Day 4｜MinIO 合并：确认 composeObject 真在存储端完成&quot;">​</a></h2><p><strong>任务</strong></p><ul><li><p>找到“合并分片”的 service 方法 bject（或等价 API）</p></li><li><p>理解：为什么它比“后端把分片拉下来再拼”更省资源</p></li></ul><p><strong>产出物</strong></p><ul><li>1 段你自己的口述稿（30 秒）：解释 composeObject 的价值<br><strong>对齐亮点</strong>：1 (<a href="https://paicoding.com/column/10/22?utm_source=chatgpt.com" title="派聪明 RAG 文件上传解析面试题预测，19 道，覆盖 Kafka ..." target="_blank" rel="noreferrer">技术派</a>)</li></ul><hr><h2 id="day-5-kafka-解耦-你要亲眼看到-合并后发消息" tabindex="-1">Day 5｜Kafka 解耦：你要亲眼看到“合并后发消息” <a class="header-anchor" href="#day-5-kafka-解耦-你要亲眼看到-合并后发消息" aria-label="Permalink to &quot;Day 5｜Kafka 解耦：你要亲眼看到“合并后发消息”&quot;">​</a></h2><p><strong>任务</strong></p><ul><li><p>找到合并完成后的 Kafka producer 发送点</p></li><li><p>把消息体结构记下来：一般只发 fileId / filePath / md5 / orgTag（而不是发整个文件）</p></li></ul><p><strong>产出物</strong></p><ul><li>Kafka 消息 payload 的结构笔记（面试官一问你就能背出来）<br><strong>对齐亮点</strong>：2 (<a href="https://paicoding.com/column/10/14" title="✅派聪明 RAG 项目文件上传解析模块设计方案 - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</li></ul><hr><h2 id="day-6-解析服务-tika-把-pdf-word-excel-变成纯文本-细节越-脏-越真实" tabindex="-1">Day 6｜解析服务：Tika 把 PDF/Word/Excel 变成纯文本（细节越“脏”越真实） <a class="header-anchor" href="#day-6-解析服务-tika-把-pdf-word-excel-变成纯文本-细节越-脏-越真实" aria-label="Permalink to &quot;Day 6｜解析服务：Tika 把 PDF/Word/Excel 变成纯文本（细节越“脏”越真实）&quot;">​</a></h2><p><strong>任务</strong></p><ul><li><p>找到 Kafka consumer（解析任务）</p></li><li><p>断点看 Tika 解析输出：表格/图片会怎样？乱码怎么处理？</p></li><li><p>记录：解析失败一般怎么兜底（返回空、标记失败状态、重试等）</p></li></ul><p><strong>产出物</strong></p><ul><li>“解析结果长什么样”的截图（变量内容/长度）<br><strong>对齐亮点</strong>：2/3 (<a href="https://paicoding.com/column/10/14" title="✅派聪明 RAG 项目文件上传解析模块设计方案 - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</li></ul><hr><h2 id="day-7-文本切分-chunk-的粒度与元数据-这是后面检索质量的根" tabindex="-1">Day 7｜文本切分：chunk 的粒度与元数据（这是后面检索质量的根） <a class="header-anchor" href="#day-7-文本切分-chunk-的粒度与元数据-这是后面检索质量的根" aria-label="Permalink to &quot;Day 7｜文本切分：chunk 的粒度与元数据（这是后面检索质量的根）&quot;">​</a></h2><p><strong>任务</strong></p><ul><li><p>找切分逻辑：按长度？按段落？有没有重叠？</p></li><li><p>记录 chunk 元信息：fileId、chunkId、顺序、原文片段等</p></li></ul><p><strong>产出物</strong></p><ul><li>1 页笔记：chunk 设计取舍（切太碎/切太大各有什么问题）<br><strong>对齐亮点</strong>：3/4 (<a href="https://paicoding.com/column/10/14" title="✅派聪明 RAG 项目文件上传解析模块设计方案 - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</li></ul><hr><h2 id="day-8-向量化-调用-embedding-→-写-es-确认-向量目前存-es" tabindex="-1">Day 8｜向量化：调用 Embedding → 写 ES（确认“向量目前存 ES”） <a class="header-anchor" href="#day-8-向量化-调用-embedding-→-写-es-确认-向量目前存-es" aria-label="Permalink to &quot;Day 8｜向量化：调用 Embedding → 写 ES（确认“向量目前存 ES”）&quot;">​</a></h2><p><strong>任务</strong></p><ul><li><p>找到向量化 consumer</p></li><li><p>断点看 embedding 返回向量维度（你必须记住维度）</p></li><li><p>找到写入 ES 的 index 代码（mapping / 字段名）</p></li></ul><p><strong>产出物</strong></p><ul><li>1 张“写 ES 的字段结构”笔记（text + vector + 元信息）<br><strong>对齐亮点</strong>：3 (<a href="https://paicoding.com/column/10/14" title="✅派聪明 RAG 项目文件上传解析模块设计方案 - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</li></ul><hr><h2 id="day-9-混合检索-把-es-query-dsl-复制出来-这是检索亮点的铁证" tabindex="-1">Day 9｜混合检索：把 ES Query DSL 复制出来（这是检索亮点的铁证） <a class="header-anchor" href="#day-9-混合检索-把-es-query-dsl-复制出来-这是检索亮点的铁证" aria-label="Permalink to &quot;Day 9｜混合检索：把 ES Query DSL 复制出来（这是检索亮点的铁证）&quot;">​</a></h2><p><strong>任务</strong></p><ul><li><p>找检索 service：定位 bool/should 或组合 query 的地方</p></li><li><p>打断点把最终 Query DSL copy 出来保存</p></li><li><p>看里面是否同时包含：关键词部分 + 向量部分</p></li></ul><p><strong>产出物</strong></p><ul><li>你保存的 Query DSL（贴到笔记里）<br><strong>对齐亮点</strong>：4 (<a href="https://paicoding.com/column/10/15%3Bjsessionid%3D2547B2D7F523EE083B197FD530342004" title="✅派聪明 RAG知识库检索模块设计方案 - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</li></ul><hr><h2 id="day-10-检索权限过滤-orgtags-怎么影响查询结果" tabindex="-1">Day 10｜检索权限过滤：orgTags 怎么影响查询结果 <a class="header-anchor" href="#day-10-检索权限过滤-orgtags-怎么影响查询结果" aria-label="Permalink to &quot;Day 10｜检索权限过滤：orgTags 怎么影响查询结果&quot;">​</a></h2><p><strong>任务</strong></p><ul><li><p>准备 2 个用户：不同 orgTags</p></li><li><p>同一个问题分别搜索，观察结果差异</p></li><li><p>定位：权限过滤是拼到 ES query 的 filter 里，还是应用层二次过滤</p></li></ul><p><strong>产出物</strong></p><ul><li>1 份对比记录：A 用户能搜到、B 用户搜不到（原因解释清楚）<br><strong>对齐亮点</strong>：5/4 (<a href="https://paicoding.com/column/10/15%3Bjsessionid%3D2547B2D7F523EE083B197FD530342004" title="✅派聪明 RAG知识库检索模块设计方案 - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</li></ul><hr><h2 id="day-11-prompt-抓住-buildmessages-prompt-工程的-唯一真相" tabindex="-1">Day 11｜Prompt：抓住 buildMessages（Prompt 工程的“唯一真相”） <a class="header-anchor" href="#day-11-prompt-抓住-buildmessages-prompt-工程的-唯一真相" aria-label="Permalink to &quot;Day 11｜Prompt：抓住 buildMessages（Prompt 工程的“唯一真相”）&quot;">​</a></h2><p><strong>任务</strong></p><ul><li><p>定位 buildMessages</p></li><li><p>记录 Prompt 结构：system（规则）/ system（检索片段）/ user（问题）/ assistant（历史）</p></li><li><p>观察：检索片段放在哪里、如何拼</p></li></ul><p><strong>产出物</strong></p><ul><li>你保存的一份 Prompt 样例（脱敏即可）<br><strong>对齐亮点</strong>：6 (<a href="https://paicoding.com/column/10/26?utm_source=chatgpt.com" title="派聪明 RAG 知识库的Prompt设计 - 技术派 - Java技术社区 ..." target="_blank" rel="noreferrer">技术派</a>)</li></ul><hr><h2 id="day-12-websocket-流式输出-你要看到-token-一段段往外吐" tabindex="-1">Day 12｜WebSocket 流式输出：你要看到 token 一段段往外吐 <a class="header-anchor" href="#day-12-websocket-流式输出-你要看到-token-一段段往外吐" aria-label="Permalink to &quot;Day 12｜WebSocket 流式输出：你要看到 token 一段段往外吐&quot;">​</a></h2><p><strong>任务</strong></p><ul><li><p>打开前端聊天，观察 WebSocket frame（浏览器开发者工具）</p></li><li><p>后端断点找到流式回写的位置（handler/发送消息）</p></li><li><p>记录：为什么选 WebSocket（双向、长连接、有状态）而不是 SSE</p></li></ul><p><strong>产出物</strong></p><ul><li>30 秒口述稿：WebSocket 的价值 + 在本项目的作用<br><strong>对齐亮点</strong>：6 (<a href="https://paicoding.com/column/10/16" title="✅派聪明 RAG 系统的聊天助手模块设计方案 - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</li></ul><hr><h2 id="day-13-把-证据包-装订成册-每个亮点-1-张图-1-段话术" tabindex="-1">Day 13｜把“证据包”装订成册：每个亮点 1 张图 + 1 段话术 <a class="header-anchor" href="#day-13-把-证据包-装订成册-每个亮点-1-张图-1-段话术" aria-label="Permalink to &quot;Day 13｜把“证据包”装订成册：每个亮点 1 张图 + 1 段话术&quot;">​</a></h2><p><strong>任务</strong></p><ul><li><p>你现在应该已经有：Bitmap、Kafka payload、Tika 结果、ES DSL、Prompt、WebSocket frames</p></li><li><p>每个亮点写 1 段 STAR（2 分钟以内）</p></li></ul><p><strong>产出物</strong></p><ul><li>《Pai‑RAG 证据包》：6 个亮点 ×（截图/笔记/话术）<br><strong>对齐亮点</strong>：1–6（全部）</li></ul><hr><h2 id="day-14-回填简历-只写你-证据包里能证明-的内容" tabindex="-1">Day 14｜回填简历：只写你“证据包里能证明”的内容 <a class="header-anchor" href="#day-14-回填简历-只写你-证据包里能证明-的内容" aria-label="Permalink to &quot;Day 14｜回填简历：只写你“证据包里能证明”的内容&quot;">​</a></h2><p><strong>任务</strong></p><ul><li><p>用我给你的 V4.0 简历文件当底稿</p></li><li><p>把你 Day13 的真实数据/描述回填（如果你测了性能，再加数字；没测就别编）</p></li></ul><p><strong>产出物</strong></p><ul><li>简历定稿版 + 你自己的面试讲稿（6 条亮点，每条 2 分钟）<br><strong>对齐亮点</strong>：1–6（全部） (<a href="https://paicoding.com/column/10/2" title="✅派聪明RAG项目如何写到简历上？（附 20 道精选 AI 面试题） - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</li></ul><hr><h1 id="结合你-2026-暑期实习-6-月中旬后到岗-的整体路线-从现在-2026-02-14-到-6-月" tabindex="-1">结合你“2026 暑期实习（6 月中旬后到岗）”的整体路线（从现在 2026/02/14 到 6 月） <a class="header-anchor" href="#结合你-2026-暑期实习-6-月中旬后到岗-的整体路线-从现在-2026-02-14-到-6-月" aria-label="Permalink to &quot;结合你“2026 暑期实习（6 月中旬后到岗）”的整体路线（从现在 2026/02/14 到 6 月）&quot;">​</a></h1><p>你不需要现在就海投，但你需要“到 6 月能上场就杀穿”⚔️<br> 我给你一个<strong>清晰、执行性强</strong>的节奏：</p><h2 id="_2-15-–-3-1-完成上面-14-天游学-拿到-pai‐rag-证据包-简历定稿" tabindex="-1">2/15 – 3/1：完成上面 14 天游学（拿到 Pai‑RAG 证据包 + 简历定稿） <a class="header-anchor" href="#_2-15-–-3-1-完成上面-14-天游学-拿到-pai‐rag-证据包-简历定稿" aria-label="Permalink to &quot;2/15 – 3/1：完成上面 14 天游学（拿到 Pai‑RAG 证据包 + 简历定稿）&quot;">​</a></h2><ul><li><p>目标：简历里 Pai‑RAG 6 条亮点都能“掏证据”</p></li><li><p>每周至少 5 天学习，保证连贯性</p></li></ul><h2 id="_3-月-巩固面试高频基础-只补-会被追问-的" tabindex="-1">3 月：巩固面试高频基础（只补“会被追问”的） <a class="header-anchor" href="#_3-月-巩固面试高频基础-只补-会被追问-的" aria-label="Permalink to &quot;3 月：巩固面试高频基础（只补“会被追问”的）&quot;">​</a></h2><p>每周 5 天，每天 1.5h（别贪多，贵在持续）</p><ul><li><p>Spring Security + JWT（认证/授权/Filter 链）</p></li><li><p>Redis（Bitmap/缓存一致性）</p></li><li><p>Kafka（消费者并发、重复消费、幂等）</p></li><li><p>Elasticsearch（倒排/BM25、向量检索基本概念、topK、filter）</p></li></ul><blockquote><p>这些全部都能从派聪明体系里长出来，不算“引入奇怪新东西”。(<a href="https://paicoding.com/column/10/1" title="✅派聪明 RAG 知识库项目上线了！AI 时代，你值得拥有！ - 技术派 - Java技术社区 | RAG+Agent实战项目教程+AI助手" target="_blank" rel="noreferrer">技术派</a>)</p></blockquote><h2 id="_4-月-把-个人网站项目-做成你的加分项-不必过度吹" tabindex="-1">4 月：把“个人网站项目”做成你的加分项（不必过度吹） <a class="header-anchor" href="#_4-月-把-个人网站项目-做成你的加分项-不必过度吹" aria-label="Permalink to &quot;4 月：把“个人网站项目”做成你的加分项（不必过度吹）&quot;">​</a></h2><ul><li><p>目标：你简历里的“工程化”是真实的、有可访问链接的</p></li><li><p>产出：站点链接 + README（写清部署方式）</p></li></ul><h2 id="_5-月-–-6-月上旬-模拟面试-定向准备-简历投递节奏" tabindex="-1">5 月 – 6 月上旬：模拟面试 + 定向准备 + 简历投递节奏 <a class="header-anchor" href="#_5-月-–-6-月上旬-模拟面试-定向准备-简历投递节奏" aria-label="Permalink to &quot;5 月 – 6 月上旬：模拟面试 + 定向准备 + 简历投递节奏&quot;">​</a></h2><ul><li><p>5 月开始：每周 2 次模拟面试（一次项目深挖、一次八股基础）</p></li><li><p><strong>投递建议</strong>：你 6 月中旬后到岗，所以可以 <strong>5 月下旬到 6 月上旬</strong> 开始投递（不早不晚，刚好）</p></li></ul><hr><h2 id="最后一句队长发言-kasumi-上线🎸✨" tabindex="-1">最后一句队长发言（Kasumi 上线🎸✨） <a class="header-anchor" href="#最后一句队长发言-kasumi-上线🎸✨" aria-label="Permalink to &quot;最后一句队长发言（Kasumi 上线🎸✨）&quot;">​</a></h2><p>你现在最强的路线不是“堆更多技术名词”，而是：<br><strong>用 Pai‑RAG 打一套“证据链打法”——我说的每一句，都能断点/日志/DSL/接口返回证明。</strong><br> 这会让你在实习面试里看起来不像“背项目”，而像“真做过的人”。</p><p>你已经有一个很好的底稿了（哪怕它有错误也没关系），我把它矫正成“对齐教程 + 面试能扛住”的版本，并把 14 天游学改成了“每一天都为简历亮点服务”的路线。继续按这个节奏冲，6 月你会非常稳 💪✨</p>',160)])])}const d=r(i,[["render",o]]);export{u as __pageData,d as default};
